using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class KanbanTraining : TrainingContentBase
{
    public KanbanTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Kanban Board Overview",
            Slug = "kanban-overview",
            Summary = "Comprehensive overview of the Kanban board — track types, stages, job cards, drag-and-drop, real-time sync, and how jobs flow through production.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 8,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/kanban"]""",
            Tags = """["kanban","jobs","board","production","drag-and-drop","signalr"]""",
            ContentJson = """
{"body":"## Kanban Board Overview\n\nThe Kanban Board is the operational heart of QB Engineer. Every job in your shop — whether it's a customer production order, an R&D prototype, a maintenance task, or an internal project — lives on the board and moves through stages from left to right as work progresses. The board gives you a real-time, at-a-glance view of everything happening in your shop.\n\n### Track Types\n\nThe board is organized by **track types**. Each track type represents a distinct workflow with its own set of stages. QB Engineer ships with four built-in track types:\n\n- **Production** — The primary workflow for customer jobs. Stages follow the quote-to-cash flow: Quote Requested → Quoted (Estimate) → Order Confirmed (Sales Order) → Materials Ordered (PO) → Materials Received → In Production → QC/Review → Shipped (Invoice) → Invoiced/Sent → Payment Received (Payment).\n- **R&D/Tooling** — For research, development, and tooling projects. Includes iteration tracking (version count and notes) for prototype cycles.\n- **Maintenance** — For equipment maintenance, facility repairs, and upkeep tasks.\n- **Other** — A catch-all for anything that doesn't fit the above categories.\n\nAdmins can create custom track types with custom stages from the Admin settings. Each track type can have its own stage colors, WIP limits, and irreversible stage flags.\n\nYou switch between track types using the **track type buttons** in the page header. The board reloads instantly when you switch, and SignalR automatically joins the correct board group for real-time updates.\n\n### Stages and Columns\n\nEach stage in a track type becomes a **column** on the board. Columns display from left to right in sort order. Each column header shows:\n\n- **Stage name** — The name of the stage.\n- **Job count** — How many jobs are currently in that column.\n- **WIP limit** — If configured, the maximum recommended jobs for the column. When exceeded, the count turns red as a visual warning.\n- **Lock icon** — Appears on irreversible stages. Jobs cannot be moved backward out of an irreversible stage (e.g., once an invoice is created at the 'Shipped' stage, you can't move the job back to 'In Production').\n- **Color stripe** — A colored top border matching the stage color for quick visual identification.\n\nEmpty columns show an empty state message encouraging you to drag jobs in.\n\n### Job Cards\n\nEach job on the board is represented by a **job card**. Cards are compact but information-dense:\n\n- **Left border color** — Indicates priority: green (Low), blue (Normal), orange (High), red (Urgent).\n- **Job number** — Clickable link that opens the full job detail dialog. Auto-generated sequential number (e.g., JOB-0001).\n- **Title** — The job's title text.\n- **Cover photo** — Optional image displayed above the card content. Uploaded via the detail panel.\n- **Hold indicator** — A pause icon appears when the job has active holds, with a tooltip listing hold reasons.\n- **Overdue warning** — A yellow warning icon appears when the job's due date has passed.\n- **Footer indicators:**\n  - Assignee avatar (initials + color)\n  - Customer name\n  - Billing status icon (invoiced/uninvoiced)\n  - Accounting document reference (e.g., QuickBooks invoice number)\n  - Disposition icon (if the job has been disposed)\n  - Sub-jobs count with tree icon\n  - Due date (turns red when overdue)\n\n### Drag-and-Drop\n\nCards can be **dragged between columns** to move jobs through stages. The move is optimistic — the card moves immediately in the UI, and if the server rejects the move (e.g., attempting to move backward from an irreversible stage), the card snaps back to its original position.\n\nWithin a column, you can **reorder cards** by dragging them up or down. Position changes are saved automatically.\n\nWhen a job moves to the **final stage** of its track type, the system automatically sets the job's completed date. Moving it backward clears the completed date.\n\nIf the target stage has an **accounting document type** configured (e.g., Invoice at the 'Shipped' stage), moving a job there automatically enqueues the document for creation in your connected accounting provider.\n\n### Multi-Select and Bulk Actions\n\nHold **Ctrl** (or **Cmd** on Mac) and click cards to select multiple jobs. A selection count badge and a **bulk action bar** appear at the bottom of the screen. Bulk actions include:\n\n- **Move** — Move all selected jobs to a chosen stage.\n- **Assign** — Assign all selected jobs to a team member (or unassign).\n- **Priority** — Set priority on all selected jobs.\n- **Archive** — Archive all selected jobs (with confirmation dialog).\n\nClick any card without Ctrl to deselect all. Click the X button in the bulk bar to clear the selection.\n\n### Board View vs. Team (Swimlane) View\n\nThe board has two view modes, toggled via icons in the header:\n\n- **Board View** (default) — Traditional kanban columns. Best for seeing the flow of work through stages.\n- **Team View** — A swimlane grid where each row is a team member and each column is a stage. Cards appear at the intersection of their assignee and current stage. Includes an 'Unassigned' row. You can drag cards between cells to simultaneously change stage and assignee.\n\n### Filtering\n\n- **Team Members** multi-select — Filter the board to show only jobs assigned to specific people.\n- **My Work** toggle — Quick filter to show only jobs assigned to you. Persists as a user preference.\n\n### Real-Time Sync (SignalR)\n\nThe board uses **SignalR WebSocket** connections for real-time updates. When another user creates a job, moves a card, updates a job, or reorders cards, your board refreshes automatically. No manual refresh needed.\n\nThe connection state is monitored — if the WebSocket disconnects, a yellow 'Reconnecting...' banner appears at the top of the page. If it fails to reconnect, the banner turns red.\n\n### Barcode Scanner Integration\n\nIf you have a USB barcode scanner connected, scanning a job number barcode while on the kanban page will automatically find and open that job's detail dialog. The scanner context is set to 'kanban' when the page loads.\n\n### Job Detail Dialog\n\nClicking a job number opens the **full job detail dialog** as a Material Dialog (not a side panel). The dialog is split into two columns:\n\n**Left column (main content):**\n- Title and description\n- R&D iteration badge (for R&D/Tooling track)\n- Disposition info (if disposed)\n- Subtasks with checkbox completion\n- Sub-jobs list with entity links\n- BOM explosion button (if the job has a linked part)\n- Linked cards (related jobs, blocking jobs, parent/child relationships)\n- Parts list with search and add\n- Cost analysis summary\n- Operation time analysis\n- Activity log, comments, notes, and history\n\n**Right column (sidebar):**\n- Status timeline with holds\n- Disposition button\n- Barcode/QR code info\n- Details metadata (priority, assignee with quick-change menu, customer, due date, start date, track type, linked part, parent job)\n- File attachments with drag-and-drop upload\n- Time entries logged against the job\n\n### Create / Edit Job Dialog\n\nThe create dialog collects: Title (required, max 200 chars), Description, Track Type (create only), Customer, Assignee, Priority, and Due Date. The edit dialog is identical but without Track Type (you can't change a job's track type after creation).\n\nDraft auto-save is enabled — if you close the dialog accidentally, your form data is recovered on next visit.\n\n### URL and Sharing\n\nThe board supports deep linking via the `?detail=job:{id}` query parameter. When you open a job detail dialog, the URL updates. You can copy-paste this URL to share a direct link to a specific job. Bookmarks and browser back/forward work correctly.","sections":[]}
"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Kanban Board — Guided Tour",
            Slug = "kanban-walkthrough",
            Summary = "A guided tour of the Kanban board: track type selector, columns, WIP limits, job cards, drag-and-drop, detail panel, create dialog, bulk actions, and view modes.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 8,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/kanban"]""",
            Tags = """["kanban","jobs","board","walkthrough"]""",
            ContentJson = """
{"appRoute":"/kanban","startButtonLabel":"Tour Kanban Board","steps":[{"element":"[data-tour='track-type-switcher']","popover":{"title":"Track Type Selector","description":"Switch between board workflows here. Each track type (Production, R&D/Tooling, Maintenance, Other, or custom) has its own set of stages. Click a track type button to load its board. The active track type is highlighted.","side":"bottom"}},{"element":".view-toggle","popover":{"title":"Board View vs. Team View","description":"Toggle between two views. Board View (columns icon) shows the traditional kanban layout — stages as columns, cards stacked vertically. Team View (people icon) shows a swimlane grid — rows are team members, columns are stages, and each card sits at the intersection of its assignee and stage. You can drag cards in both views.","side":"bottom"}},{"element":"[data-tour='board-filters']","popover":{"title":"Team Members Filter","description":"Filter the board by team member. Select one or more people to see only their assigned jobs. Leave empty to show all jobs. In Team View, this controls which user rows appear in the swimlane.","side":"bottom"}},{"element":".my-work-btn","popover":{"title":"My Work Toggle","description":"Quick-filter to see only jobs assigned to you. This setting persists in your user preferences — it stays active even if you leave and come back. Click again to show all jobs.","side":"bottom"}},{"element":"[data-testid='new-job-btn']","popover":{"title":"Create New Job","description":"Opens the job creation dialog. You'll fill in Title (required), Description, Track Type, Customer, Assignee, Priority, and Due Date. The job number is auto-generated. The new job lands in the first stage of the selected track type. Draft auto-save protects your form data if you accidentally close the dialog.","side":"bottom"}},{"element":"[data-tour='board-columns']","popover":{"title":"Board Columns and Hint Bar","description":"This hint bar reminds you that cards are draggable. Hold Ctrl (or Cmd on Mac) and click cards to multi-select for bulk actions. The hint disappears when you have cards selected, replaced by the bulk action bar.","side":"bottom"}},{"element":"[data-tour='wip-limit']","popover":{"title":"Column Header","description":"Each column shows the stage name, current job count, and WIP (Work-In-Progress) limit if configured. When the count exceeds the WIP limit, the count turns red as a visual warning. A lock icon (🔒) indicates an irreversible stage — jobs cannot be moved backward from it. The colored top border matches the stage color.","side":"bottom"}},{"element":"[data-tour='job-card']","popover":{"title":"Job Card","description":"Each card shows the job at a glance. The left border color indicates priority (green=Low, blue=Normal, orange=High, red=Urgent). The header shows the clickable job number and indicators for holds (pause icon) and overdue status (warning icon). The footer shows assignee avatar, customer name, billing status, sub-job count, and due date. Click the job number to open the full detail dialog. Ctrl+Click to multi-select.","side":"right"}},{"element":".column","popover":{"title":"Drag-and-Drop","description":"Drag cards between columns to move jobs through stages. The move is optimistic — the card moves instantly, and if the server rejects it (e.g., backward from an irreversible stage), it snaps back. Within a column, drag to reorder. Position is saved automatically. In Team View, dragging between cells can change both stage and assignee simultaneously.","side":"top"}}]}
"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Kanban Board Field Reference",
            Slug = "kanban-field-reference",
            Summary = "Complete reference for every field, button, status, tab, validation rule, and action on the Kanban board, job cards, create/edit dialog, and job detail dialog.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 8,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/kanban"]""",
            Tags = """["kanban","jobs","board","reference","fields"]""",
            ContentJson = """
{"title":"Kanban Board Field Reference","groups":[{"heading":"Job Card Fields","items":[{"label":"Left Border Color","value":"Indicates job priority. Green = Low, Blue = Normal, Orange = High, Red = Urgent. Always visible on every card."},{"label":"Job Number","value":"Auto-generated sequential identifier (e.g., JOB-0001). Clickable — opens the full job detail dialog. Displayed in the card header with monospace-style font."},{"label":"Title","value":"The job's title text. Displayed below the header. Truncated with ellipsis if too long for the card width."},{"label":"Cover Photo","value":"Optional image displayed above the card content. Uploaded via the detail panel's cover photo button. Shows as a cropped banner at the top of the card."},{"label":"Hold Indicator","value":"Pause circle icon (⏸) in the card header. Appears when the job has one or more active holds. Tooltip lists all active hold reasons on hover."},{"label":"Overdue Warning","value":"Yellow warning triangle icon in the card header. Appears when the job's due date has passed and the job is not yet completed."},{"label":"Assignee Avatar","value":"Circular avatar in the footer showing the assignee's initials and color. Hidden when no assignee is set."},{"label":"Customer Name","value":"Text in the footer showing the customer associated with the job. Hidden when no customer is set."},{"label":"Billing Status Icon","value":"Dollar icon in the footer. Green checkmark for 'Invoiced', orange pending icon for 'Uninvoiced'. Only appears when a billing status exists."},{"label":"Accounting Reference","value":"Receipt icon + reference number in the footer. Shows the external accounting document reference (e.g., QuickBooks invoice number). Only appears when the job has an accounting integration link."},{"label":"Disposition Icon","value":"Checkmark icon in the footer. Appears when the job has been disposed (shipped, inventoried, scrapped, etc.)."},{"label":"Sub-Jobs Count","value":"Tree icon + number in the footer. Shows how many child jobs exist under this job. Only appears when count > 0."},{"label":"Due Date","value":"Date text in the footer, formatted MM/dd/yyyy. Turns red when the job is overdue. Hidden when no due date is set."},{"label":"Selected State","value":"When a card is multi-selected (Ctrl+Click), it shows a blue check mark overlay and a highlighted border."}]},{"heading":"Create Job Dialog Fields","items":[{"label":"Title (required)","value":"Text input, max 200 characters. The name of the job. Cannot be empty. data-testid: job-title"},{"label":"Description","value":"Textarea, optional. Free-form description of the job's scope, requirements, or notes. 3 rows by default. data-testid: job-description"},{"label":"Track Type (required, create only)","value":"Dropdown. Selects which workflow track the job belongs to (Production, R&D/Tooling, Maintenance, Other, or custom). Not shown in edit mode — track type cannot be changed after creation. The job enters the first stage of the selected track. data-testid: job-track-type"},{"label":"Customer","value":"Dropdown populated from the customers database. Optional — select '-- None --' to create a job without a customer. data-testid: job-customer"},{"label":"Assignee","value":"Dropdown populated from the users database. Optional — select '-- Unassigned --' for no assignee. Users who have not completed their profile/onboarding are shown with a warning icon (⚠) and '(incomplete profile)' label. data-testid: job-assignee"},{"label":"Priority","value":"Dropdown: Low, Normal (default), High, Urgent. Determines the card's left border color on the board. data-testid: job-priority"},{"label":"Due Date","value":"Date picker. Optional. When set, the card shows the date in its footer and displays an overdue warning if the date has passed. Sent to the API as an ISO UTC string. data-testid: job-due-date"},{"label":"Save Button","value":"Disabled when the form is invalid or a save is in progress. Shows a spinner icon while saving. Hover shows a validation popover listing any violations. data-testid: job-save-btn"},{"label":"Draft Auto-Save","value":"The dialog automatically saves form state to IndexedDB as you type (2.5s debounce). If you close the dialog accidentally, your data is recovered on next visit with a recovery banner."}]},{"heading":"Job Detail Dialog — Header","items":[{"label":"Job Number","value":"Displayed in bold in the top-left. Non-editable."},{"label":"Stage Chip","value":"Colored chip next to the job number showing the current stage name. Color matches the stage color configured in admin."},{"label":"Timer Button (Start)","value":"Play circle icon. Starts a time tracking timer for this job. Disabled while timer action is loading. Tooltip: 'Start Timer'."},{"label":"Timer Button (Stop)","value":"Stop circle icon with active styling. Appears when a timer is running for this job. Stops the active timer. Tooltip: 'Stop Timer'."},{"label":"Cover Photo Button","value":"Camera/add-photo icon. Opens the cover photo upload dialog to set or change the card's cover image. Tooltip: 'Set Cover Photo'."},{"label":"Edit Button","value":"Edit icon. Opens the edit job dialog pre-filled with current values. Tooltip: 'Edit Job'."},{"label":"Close Button","value":"Close (X) icon. Closes the detail dialog and clears the ?detail= URL parameter. Tooltip: 'Close'."}]},{"heading":"Job Detail — Main Content Sections","items":[{"label":"Title & Description","value":"The hero section shows the job title as an h1 heading and the description below it. If no description exists, shows 'No description' in muted text."},{"label":"R&D Iteration Badge","value":"Shown only for R&D/Tooling track jobs or when iteration count > 0. Displays 'R&D Iteration' heading with version number (e.g., v3) and optional iteration notes text."},{"label":"Disposition Info","value":"Shown only when the job has been disposed. Displays disposition type (Ship to Customer, Add to Inventory, Capitalize as Asset, Scrap, Hold for Review), optional notes, and disposition date."},{"label":"Subtasks Section","value":"Checkbox list of subtasks with completion counter (e.g., 3/5). Check/uncheck toggles completion. Add new subtasks via the text input + add button at the bottom. Press Enter to add quickly. Subtask text is displayed with strikethrough when completed."},{"label":"Sub-Jobs Section","value":"List of child jobs (created via BOM explosion or manual linking). Each shows the job number (clickable entity link), title, and current stage chip. Only shown when child jobs exist."},{"label":"Explode BOM Button","value":"Shown when the job has a linked part and no existing child jobs. Creates child jobs from the part's bill of materials. Each BOM entry becomes a child job with the same track type."},{"label":"Linked Cards Section","value":"Shows relationships to other jobs. Each link shows an icon, type label (Related to, Blocks, Parent of), the linked job number (clickable entity link), title, stage chip, and a delete button. Add new links via the search input + type selector + add button."},{"label":"Parts Section","value":"Parts attached to this job. Each shows a gear icon, part number (clickable entity link), description, quantity, and a remove button. Add parts via the search input + add button."},{"label":"Cost Analysis Section","value":"Embedded cost summary tab showing estimated material, labor, burden, and subcontract costs. Displays quoted price and calculated margin percentage."},{"label":"Operation Time Section","value":"Embedded operation time analysis tab showing time breakdowns by operation for the job."},{"label":"Activity / Comments / Notes / History","value":"Shared entity activity section showing a chronological feed of all changes, comments, notes, and system events for the job. Supports inline commenting with @mentions."}]},{"heading":"Job Detail — Sidebar Sections","items":[{"label":"Status Timeline","value":"Shows the job's workflow progression through stages, including any active holds. Uses the shared StatusTimelineComponent. Displays stage names, timestamps, and hold reasons."},{"label":"Dispose Button","value":"Opens the Dispose Job dialog. Only shown when the job has not yet been disposed. Options: Ship to Customer, Add to Inventory, Capitalize as Asset, Scrap, Hold for Review."},{"label":"Barcode / QR Info","value":"Compact barcode section showing the job's barcode for scanning. Uses the shared BarcodeInfoComponent."},{"label":"Priority (sidebar)","value":"Displays the job's priority with a colored dot. Low = green, Normal = blue, High = orange, Urgent = red."},{"label":"Assignee (sidebar, clickable)","value":"Shows the current assignee's avatar and name. Click to open a dropdown menu to reassign. Options include 'Unassign' and all team members with avatars. Changes save immediately without opening the edit dialog."},{"label":"Customer (sidebar)","value":"Shows the customer name as a clickable entity link navigating to the customer detail page. Shows '—' when no customer."},{"label":"Due Date (sidebar)","value":"Displays the due date formatted MM/dd/yyyy. Shows nothing when not set."},{"label":"Start Date (sidebar)","value":"Displays the start date formatted MM/dd/yyyy. Automatically set when the job is first moved from its initial stage."},{"label":"Track Type (sidebar)","value":"Displays the track type name (Production, R&D/Tooling, etc.). Read-only."},{"label":"Part (sidebar)","value":"Shown when the job has a linked primary part. Displays the part number as a clickable entity link."},{"label":"Parent Job (sidebar)","value":"Shown when the job is a child of another job. Displays the parent job number as a clickable entity link."},{"label":"Files Section","value":"Drag-and-drop file upload zone (accepts any file type) plus a list of attached files. Each file shows a type icon, file name, size + upload date, download button, and delete button."},{"label":"Time Section","value":"Lists all time entries logged against this job. Each entry shows user name, date, duration (formatted as Xh Ym), and optional notes. Header shows total time across all entries."}]},{"heading":"Dispose Job Dialog Fields","items":[{"label":"Disposition (required)","value":"Dropdown: Ship to Customer, Add to Inventory, Capitalize as Asset, Scrap, Hold for Review. Determines what happens to the job's output."},{"label":"Notes","value":"Textarea, optional, max 2000 characters. Additional context for the disposition decision."},{"label":"Dispose Button","value":"Saves the disposition and marks the job as disposed. Disabled when form is invalid."}]},{"heading":"Job Statuses (Stage Flow)","items":[{"label":"Quote Requested","value":"Initial stage for Production track. Job has been requested but not yet quoted."},{"label":"Quoted (Estimate)","value":"An estimate has been prepared. May trigger accounting document creation if connected."},{"label":"Order Confirmed (Sales Order)","value":"Customer has accepted the quote and a sales order is created."},{"label":"Materials Ordered (PO)","value":"Purchase orders have been created for required materials."},{"label":"Materials Received","value":"All ordered materials have arrived and are ready for production."},{"label":"In Production","value":"Active manufacturing/production work is underway."},{"label":"QC/Review","value":"Quality control inspection and review phase."},{"label":"Shipped (Invoice)","value":"Job output has been shipped. May trigger invoice creation. Often an irreversible stage."},{"label":"Invoiced/Sent","value":"Invoice has been sent to the customer."},{"label":"Payment Received (Payment)","value":"Final stage. Customer payment has been received. Job is marked completed."}]},{"heading":"Priority Levels","items":[{"label":"Low (green)","value":"Non-urgent work. Card left border is green. Lowest priority in sorting."},{"label":"Normal (blue)","value":"Default priority for all new jobs. Card left border is blue."},{"label":"High (orange)","value":"Important work that should be addressed soon. Card left border is orange."},{"label":"Urgent (red)","value":"Critical work requiring immediate attention. Card left border is red. Highest priority in sorting."}]},{"heading":"Bulk Actions","items":[{"label":"Multi-Select","value":"Hold Ctrl (Cmd on Mac) and click cards to select multiple jobs. Selected cards show a blue check overlay. Click any card without Ctrl to deselect all."},{"label":"Bulk Move","value":"Move all selected jobs to a target stage. Opens a menu showing all stages for the current track type. Each stage shows its color dot. Success snackbar shows count of moved jobs."},{"label":"Bulk Assign","value":"Assign all selected jobs to a team member. Menu shows 'Unassign' option plus all team members. Success snackbar shows count and assignee name."},{"label":"Bulk Set Priority","value":"Set priority on all selected jobs. Menu shows Low, Normal, High, Urgent. Success snackbar shows the priority and count."},{"label":"Bulk Archive","value":"Archive all selected jobs. Opens a confirmation dialog ('Are you sure? This will remove X jobs from the board. You can restore them later.'). Archived jobs are soft-deleted, not permanently removed. Success snackbar shows count."},{"label":"Clear Selection","value":"X button on the right side of the bulk bar. Clears all selected cards."}]},{"heading":"Keyboard and Interaction Shortcuts","items":[{"label":"Ctrl+Click card","value":"Toggle multi-select on a card. Adds or removes the card from the current selection."},{"label":"Enter on card","value":"Opens the job detail dialog for the focused card (keyboard navigation support)."},{"label":"Escape (detail dialog)","value":"Closes the job detail dialog."},{"label":"Enter in subtask input","value":"Adds the typed subtask text to the subtask list without clicking the add button."},{"label":"Barcode scan","value":"When on the kanban page with a USB barcode scanner, scanning a job number barcode automatically finds and opens that job's detail dialog."}]},{"heading":"Column Header Elements","items":[{"label":"Stage Name","value":"The name of the stage. Displayed in the column header."},{"label":"Job Count","value":"Number of jobs currently in this column. Updates in real-time via SignalR."},{"label":"WIP Limit","value":"Maximum recommended jobs for the column, shown as '/ N' after the count. Configured per-stage by admins. When exceeded, the display turns red."},{"label":"Lock Icon","value":"Padlock icon on irreversible stages. Jobs cannot be dragged backward out of these stages. Tooltip explains: 'Documents created at this stage cannot be voided.'"},{"label":"Color Stripe","value":"Colored top border matching the stage's configured color. Provides visual identification for each column."}]},{"heading":"WIP Limits","items":[{"label":"Purpose","value":"Work-In-Progress limits prevent overloading a stage. They are advisory — you can still move jobs into a column that exceeds its WIP limit, but the count turns red as a warning."},{"label":"Configuration","value":"Set per-stage by admins in Admin → Track Types → Stages. Enter 0 or leave blank for no limit."},{"label":"Visual Warning","value":"When a column's job count exceeds its WIP limit, the count number and the '/ N' limit display turn red. The column body border may also shift to indicate overload."},{"label":"Enforcement","value":"WIP limits are visual warnings only — they do not block job movement. This allows flexibility for urgent situations while still surfacing bottlenecks."}]},{"heading":"Validation Rules","items":[{"label":"Title (Create/Edit)","value":"Required. Cannot be empty. Maximum 200 characters. Violation message: 'Title is required.'"},{"label":"Track Type (Create)","value":"Required. Must select a valid track type. A default track type is pre-selected if one exists. Violation message: 'Track Type is required.'"},{"label":"Backward Move Restriction","value":"Cannot move a job backward (to a lower sort-order stage) from an irreversible stage. The API returns an error and the UI snaps the card back. Error message: 'Cannot move backward from irreversible stage.'"},{"label":"Cross-Track Move","value":"Cannot move a job to a stage that belongs to a different track type. The API rejects such moves with an error."},{"label":"Assignee Compliance","value":"When assigning a job, the system checks if the assignee has completed their compliance profile. Users with incomplete profiles show a warning icon (⚠) in the assignee dropdown but can still be assigned."},{"label":"Disposition (required)","value":"When disposing a job, the disposition type must be selected. Notes are optional (max 2000 chars)."},{"label":"Subtask Text","value":"The add-subtask button is disabled when the input is empty or whitespace-only."},{"label":"Link Target","value":"The add-link button is disabled when no target job has been selected from the search results."}]},{"heading":"Board and Table Actions","items":[{"label":"Track Type Switch","value":"Click a track type button to load that track's board. The board fully reloads and SignalR joins the new board group."},{"label":"View Mode Toggle","value":"Board View (view_column icon) or Team View (people icon). Board View is the default column layout. Team View shows a swimlane grid by user."},{"label":"Drag Card Between Columns","value":"Moves the job to the target stage. Optimistic UI — card moves immediately, server confirms or rolls back."},{"label":"Drag Card Within Column","value":"Reorders the card's position within the stage. Position is saved automatically."},{"label":"Drag Card in Swimlane","value":"In Team View, dragging between cells can change both the stage (column) and assignee (row) simultaneously."},{"label":"Click Job Number","value":"Opens the full job detail dialog. Updates the URL to ?detail=job:{id} for sharing."},{"label":"Click Card (no modifier)","value":"If cards are selected, clears selection. Otherwise opens the job detail dialog."},{"label":"Edit Job (detail dialog)","value":"Opens the edit dialog pre-filled with current values. Saves changes and refreshes the board."},{"label":"Quick-Assign (detail sidebar)","value":"Click the assignee row in the sidebar to open a dropdown menu. Select a user to reassign immediately without opening the edit dialog."},{"label":"Add Subtask","value":"Type in the subtask input and press Enter or click the add button. Subtask appears immediately in the list."},{"label":"Toggle Subtask","value":"Click the checkbox on a subtask to toggle its completion status. The text gets strikethrough when completed."},{"label":"Add Link","value":"Search for a job in the link search input, select it from results, choose a link type (Related to, Blocks, Parent of), and click add."},{"label":"Remove Link","value":"Click the X button on a linked card to remove the relationship."},{"label":"Add Part","value":"Search for a part in the part search input, select it from results, and click add. Part appears in the parts list with its quantity."},{"label":"Remove Part","value":"Click the X button on a part item to detach it from the job."},{"label":"Explode BOM","value":"Click the 'Explode BOM' button on a job with a linked part. Creates child jobs from the bill of materials. Only shown when the job has a part and no existing child jobs."},{"label":"Start/Stop Timer","value":"Click the timer button in the detail header to start tracking time for this job. Click again to stop. Time entries appear in the sidebar Time section."},{"label":"Upload File","value":"Drag files onto the upload zone in the sidebar, or click to browse. Files upload with progress bars and appear in the file list."},{"label":"Download File","value":"Click the download icon on a file item to download it."},{"label":"Delete File","value":"Click the red delete icon on a file item to remove it (soft delete — file preserved in storage)."},{"label":"Dispose Job","value":"Click the Dispose button in the sidebar. Opens a dialog to select disposition type and add notes. Options: Ship to Customer, Add to Inventory, Capitalize as Asset, Scrap, Hold for Review."}]},{"heading":"Link Types","items":[{"label":"Related to","value":"General relationship between two jobs. Bidirectional — both jobs show the link. Icon: link."},{"label":"Blocks","value":"This job blocks the linked job from progressing. Used for dependency tracking. Icon: block."},{"label":"Parent of","value":"This job is the parent of the linked job. Used for hierarchical job structures. Icon: account_tree."}]}]}
"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Kanban Board Knowledge Check",
            Slug = "kanban-quiz",
            Summary = "Test your knowledge of the Kanban board: track types, stages, job cards, drag-and-drop, bulk actions, WIP limits, detail dialog, and real-time sync.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 8,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["kanban","jobs","board","quiz"]""",
            ContentJson = """
{"passingScore":80,"questionsPerQuiz":10,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"kb1","text":"You need to create a new production job for a customer order. What is the correct sequence?","options":[{"id":"a","text":"Go to the Kanban board, click 'New Job', fill in Title, select Production track type, choose the customer, set priority, and click Save","isCorrect":true},{"id":"b","text":"Go to Admin → Jobs → Add New and enter all the job details there"},{"id":"c","text":"Create a Sales Order first, then the system auto-generates the job"},{"id":"d","text":"Go to the Backlog page and drag a card to the board"}],"explanation":"Jobs are created directly from the Kanban board using the 'New Job' button. Fill in the required Title, select the track type (Production for customer orders), and optionally set customer, assignee, priority, and due date. The job number is auto-generated and the job starts in the first stage."},{"id":"kb2","text":"A job card on the board has a red left border and a yellow warning triangle. What does this tell you?","options":[{"id":"a","text":"The job is Urgent priority and is overdue","isCorrect":true},{"id":"b","text":"The job has errors and needs immediate attention from an admin"},{"id":"c","text":"The job is on hold and cannot be moved"},{"id":"d","text":"The job has been flagged for quality review"}],"explanation":"The left border color indicates priority: red = Urgent. The yellow warning triangle indicates the job's due date has passed (overdue). Together they tell you this is an urgent job that is already late."},{"id":"kb3","text":"You try to drag a job card backward from the 'Shipped' column, but it snaps back to its original position. Why?","options":[{"id":"a","text":"The 'Shipped' stage is marked as irreversible because an accounting document (invoice) was created at that stage","isCorrect":true},{"id":"b","text":"You don't have permission to move cards on this board"},{"id":"c","text":"The job is locked because it has a customer assigned"},{"id":"d","text":"Backward moves are never allowed on the kanban board"}],"explanation":"Stages can be marked as irreversible (shown with a lock icon). The 'Shipped' stage typically creates an invoice, making it irreversible — you can't undo the accounting document. The card snaps back to its position with an error. Backward moves are allowed from non-irreversible stages."},{"id":"kb4","text":"You want to reassign 8 jobs from one team member to another as quickly as possible. What is the most efficient method?","options":[{"id":"a","text":"Ctrl+Click all 8 job cards, then use the Assign button in the bulk action bar to select the new assignee","isCorrect":true},{"id":"b","text":"Open each job's detail dialog one at a time and change the assignee"},{"id":"c","text":"Use the Team View, create a filter for the old assignee, then drag each card to the new assignee's row one by one"},{"id":"d","text":"Go to Admin → Users → Reassign Jobs and enter the new assignee"}],"explanation":"Multi-select with Ctrl+Click lets you select multiple cards, then the bulk action bar's Assign button reassigns all of them in one operation. This is the fastest way to bulk-reassign jobs."},{"id":"kb5","text":"A column header shows '7 / 5' in red. What does this mean and what should you do?","options":[{"id":"a","text":"The column has 7 jobs but the WIP limit is 5 — the stage is overloaded and you should move some jobs forward or redistribute work","isCorrect":true},{"id":"b","text":"7 jobs out of 5 have been completed in this stage — the stage is performing well"},{"id":"c","text":"The column has 5 jobs but the maximum allowed is 7 — you have room for 2 more"},{"id":"d","text":"7 jobs failed validation and 5 are blocked — contact an admin"}],"explanation":"WIP (Work-In-Progress) limits are advisory thresholds set per-stage. When exceeded (7 jobs vs. 5 limit), the count turns red as a visual warning that the stage is overloaded. This indicates a bottleneck — consider moving jobs forward, rebalancing work, or addressing blockers."},{"id":"kb6","text":"What happens when you move a job to the final stage of its track type?","options":[{"id":"a","text":"The system automatically sets the job's completed date to the current timestamp","isCorrect":true},{"id":"b","text":"The job is permanently archived and removed from the board"},{"id":"c","text":"An invoice is automatically generated and sent to the customer"},{"id":"d","text":"Nothing special — it's treated the same as any other stage move"}],"explanation":"When a job reaches the final stage, the system sets its CompletedDate to the current UTC timestamp. The job remains on the board (it's not archived automatically). If the job is later moved backward from the final stage, the completed date is cleared."},{"id":"kb7","text":"You're viewing the Kanban board and another team member creates a new job. How does your board update?","options":[{"id":"a","text":"The board updates automatically in real-time via SignalR WebSocket — the new card appears without you needing to refresh","isCorrect":true},{"id":"b","text":"You need to manually click a Refresh button to see the new job"},{"id":"c","text":"The board polls the server every 30 seconds and updates on the next cycle"},{"id":"d","text":"You need to navigate away and back to the kanban page to see the update"}],"explanation":"The Kanban board uses SignalR WebSocket connections for real-time sync. When any user creates a job, moves a card, updates a job, or reorders cards, a boardHub event fires and all connected clients automatically reload the board data."},{"id":"kb8","text":"What is the difference between Board View and Team View?","options":[{"id":"a","text":"Board View shows columns by stage with cards stacked vertically; Team View shows a swimlane grid where rows are team members and columns are stages","isCorrect":true},{"id":"b","text":"Board View is for managers and Team View is for individual contributors — they show different data based on your role"},{"id":"c","text":"Board View shows all jobs and Team View only shows your assigned jobs"},{"id":"d","text":"Board View is the live board and Team View is a planning/forecast view"}],"explanation":"Board View is the traditional kanban column layout. Team View adds a user dimension — each row represents a team member (plus an Unassigned row), and cards appear at the intersection of their assignee and stage. You can drag cards in both views, and in Team View, dragging between cells can change both stage and assignee simultaneously."},{"id":"kb9","text":"You open a job detail dialog and want to quickly reassign the job without opening the edit dialog. How?","options":[{"id":"a","text":"Click the assignee row in the sidebar Details section to open a dropdown menu, then select the new assignee","isCorrect":true},{"id":"b","text":"You must click the Edit button and change the assignee in the edit dialog"},{"id":"c","text":"Drag the job card to a different row in Team View"},{"id":"d","text":"Right-click the job card and select 'Reassign' from the context menu"}],"explanation":"The assignee row in the detail sidebar is clickable and opens a mat-menu dropdown with all team members and an 'Unassign' option. Selecting a user reassigns the job immediately without needing to open the full edit dialog."},{"id":"kb10","text":"A job has a linked part and no child jobs. What does the 'Explode BOM' button do?","options":[{"id":"a","text":"Creates child jobs from the part's bill of materials — each BOM entry becomes a separate child job on the same track type","isCorrect":true},{"id":"b","text":"Breaks the job into smaller subtasks based on the part's operations"},{"id":"c","text":"Generates a purchase order for all the materials needed for the part"},{"id":"d","text":"Opens a 3D view of the part's assembly structure"}],"explanation":"BOM Explosion takes the bill of materials from the job's linked part and creates a child job for each BOM entry. This is useful for complex assemblies where each component needs its own production tracking. The button only appears when the job has a linked part and no existing child jobs."},{"id":"kb11","text":"You accidentally closed the Create Job dialog after filling in several fields. What happens to your form data?","options":[{"id":"a","text":"The dialog has draft auto-save — your form data is saved to IndexedDB and recovered with a banner the next time you open the dialog","isCorrect":true},{"id":"b","text":"All data is lost and you need to re-enter everything"},{"id":"c","text":"The data is temporarily held in memory and available if you click 'New Job' again within 60 seconds"},{"id":"d","text":"A confirmation dialog prevents you from closing if the form has unsaved data"}],"explanation":"The create/edit job dialogs use the draft auto-save system. Form state is automatically saved to IndexedDB every 2.5 seconds. If you close accidentally (or the browser crashes), the next time you open the dialog a 'Recovered unsaved changes' banner appears, and your form data is restored."},{"id":"kb12","text":"How do you share a direct link to a specific job with a coworker?","options":[{"id":"a","text":"Open the job detail dialog — the URL updates to include ?detail=job:{id}. Copy the URL from the browser address bar and share it.","isCorrect":true},{"id":"b","text":"Click the Share button in the job detail dialog to generate a shareable link"},{"id":"c","text":"Right-click the job card and select 'Copy Link'"},{"id":"d","text":"You can only share job numbers — there are no direct links to specific jobs"}],"explanation":"When you open a job detail dialog, the URL automatically updates to include ?detail=job:{id} (e.g., /kanban?detail=job:1055). Anyone who opens this URL will land on the kanban board with that job's detail dialog already open. This works with bookmarks and browser history too."},{"id":"kb13","text":"You scan a barcode with a USB scanner while on the Kanban board. What happens?","options":[{"id":"a","text":"The system searches for a job matching the scanned job number and, if found, automatically opens its detail dialog with a success snackbar","isCorrect":true},{"id":"b","text":"The scanned value is entered into the team members filter field"},{"id":"c","text":"Nothing — barcode scanning only works on the Inventory and Parts pages"},{"id":"d","text":"A new job is created with the scanned value as the title"}],"explanation":"The Kanban page sets the scanner context to 'kanban'. When a barcode is scanned, the system searches all jobs on the current board for a matching job number. If found, it opens the detail dialog and shows a success snackbar. If not found, it shows an error snackbar."},{"id":"kb14","text":"What are the three types of job links you can create between cards?","options":[{"id":"a","text":"Related to (general relationship), Blocks (dependency), and Parent of (hierarchy)","isCorrect":true},{"id":"b","text":"Duplicate, Predecessor, and Successor"},{"id":"c","text":"Depends on, Required by, and Same as"},{"id":"d","text":"Before, After, and Parallel"}],"explanation":"QB Engineer supports three link types: 'Related to' for general relationships between jobs, 'Blocks' for dependency tracking (this job blocks the linked job), and 'Parent of' for hierarchical structures (this job is the parent of the linked job)."},{"id":"kb15","text":"When you move a job card to a stage that has an accounting document type configured (e.g., Invoice), what happens automatically?","options":[{"id":"a","text":"If an accounting provider is connected and the job has a customer with an external ID, the system enqueues the document (e.g., invoice) for creation in the accounting system","isCorrect":true},{"id":"b","text":"An invoice is immediately created and sent to the customer via email"},{"id":"c","text":"The job card turns green to indicate it has been invoiced"},{"id":"d","text":"Nothing automatic — you must manually create the invoice from the Sales Orders page"}],"explanation":"When a stage has an AccountingDocumentType configured, moving a job there triggers an enqueue operation. The system checks: (1) is an accounting provider connected, (2) does the job have a customer, and (3) does the customer have an external ID (linked to the accounting system). If all conditions are met, the document creation is queued for processing."},{"id":"kb16","text":"You see a pause icon (⏸) in a job card's header. What does this indicate?","options":[{"id":"a","text":"The job has one or more active holds — hover over the icon to see the hold reasons in a tooltip","isCorrect":true},{"id":"b","text":"The job's timer is currently paused"},{"id":"c","text":"The job is waiting for customer approval"},{"id":"d","text":"The job is in a paused/maintenance stage and cannot be moved"}],"explanation":"The pause circle icon appears on job cards that have active holds. Holds are set via the Status Timeline in the detail dialog (e.g., 'Waiting for Materials', 'Customer Review'). Hovering over the icon shows a tooltip listing all active hold reasons."},{"id":"kb17","text":"In Team View, you drag a card from Alice's row in the 'In Production' column to Bob's row in the 'QC/Review' column. What happens?","options":[{"id":"a","text":"The job is both moved to the QC/Review stage and reassigned from Alice to Bob simultaneously","isCorrect":true},{"id":"b","text":"Only the stage changes to QC/Review — the assignee stays as Alice"},{"id":"c","text":"Only the assignee changes to Bob — the stage stays at In Production"},{"id":"d","text":"An error occurs — you can only change one attribute at a time"}],"explanation":"In Team View, each cell represents the intersection of a user (row) and stage (column). Dragging between cells can change both the stage and the assignee in a single drag operation. The system sends two separate API calls — one for the stage move and one for the assignee change."},{"id":"kb18","text":"You want to see only your assigned jobs on the board and have this preference persist across sessions. Which approach is correct?","options":[{"id":"a","text":"Click the 'My Work' toggle button in the header — it filters to your jobs and saves the preference so it persists when you return","isCorrect":true},{"id":"b","text":"Use the Team Members filter and select only yourself — but you'll need to reselect each time you visit"},{"id":"c","text":"Go to Account → Settings → Default Board Filter and set it to 'My Jobs Only'"},{"id":"d","text":"There is no way to persist board filters — you must set them each time"}],"explanation":"The 'My Work' toggle button filters the board to show only jobs assigned to you and saves this preference to your user preferences store. The setting persists across sessions and is also reflected in the URL as ?myWork=true. The Team Members filter works too but does not persist."},{"id":"kb19","text":"What are the five disposition types when disposing a completed job?","options":[{"id":"a","text":"Ship to Customer, Add to Inventory, Capitalize as Asset, Scrap, and Hold for Review","isCorrect":true},{"id":"b","text":"Complete, Cancel, Return, Rework, and Archive"},{"id":"c","text":"Deliver, Store, Transfer, Dispose, and Recycle"},{"id":"d","text":"Accept, Reject, Rework, Quarantine, and Ship"}],"explanation":"Job disposition determines what happens to the job's output: Ship to Customer (deliver the product), Add to Inventory (stock the finished goods), Capitalize as Asset (register as a tooling/equipment asset), Scrap (discard as waste), or Hold for Review (keep for further evaluation). Each has different downstream effects."},{"id":"kb20","text":"The SignalR connection banner at the top of the page turns yellow and says 'Reconnecting...'. What is happening and what should you do?","options":[{"id":"a","text":"The WebSocket connection to the server was interrupted and is automatically attempting to reconnect — wait a few seconds, and the board will resume real-time updates once reconnected","isCorrect":true},{"id":"b","text":"The server is shutting down for maintenance — save your work and close the application"},{"id":"c","text":"Your session has expired — you need to log in again"},{"id":"d","text":"Another user has taken control of the board — you are now in read-only mode"}],"explanation":"The ConnectionBannerComponent monitors the SignalR connection state. Yellow 'Reconnecting...' means the WebSocket dropped (network blip, server restart, etc.) and the client is automatically attempting to reconnect with exponential backoff. Usually it reconnects within seconds. If it fails completely, the banner turns red ('Disconnected'). The board continues to work but won't receive real-time updates until reconnected."}]}
"""
        });

        Log.Information("Seeded Kanban training modules");
    }
}
